    if not Details then return end
    local backupKey = "DetailsDB" .. contentType
    local otherContentType = (contentType == "PvP" and "PvE") or "PvP"
    local otherBackupKey = "DetailsDB" .. otherContentType

    -- Check if a backup for the other content type exists
    if SkillCappedBackupDB[otherBackupKey] then
        SkillCappedBackupDB[backupKey] = SkillCappedBackupDB[otherBackupKey]
        if SkillCappedBackupDB[otherBackupKey .. "AlwaysUseProfile"] then
            SkillCappedBackupDB[backupKey .. "AlwaysUseProfile"] = SkillCappedBackupDB[otherBackupKey .. "AlwaysUseProfile"]
            SkillCappedBackupDB[backupKey .. "AlwaysUseProfileName"] = SkillCappedBackupDB[otherBackupKey .. "AlwaysUseProfileName"]
        end
    else
        if not SkillCappedBackupDB[backupKey] then
            SkillCappedBackupDB[backupKey] = Details:GetCurrentProfileName() -- Details:ExportCurrentProfile()
            if _detalhes_global and _detalhes_global.always_use_profile then
                SkillCappedBackupDB[backupKey .. "AlwaysUseProfile"] = _detalhes_global.always_use_profile
                SkillCappedBackupDB[backupKey .. "AlwaysUseProfileName"] = _detalhes_global.always_use_profile_name
            end
            SkillCappedBackupDB.addonBackupTimes["Details" .. contentType] = SC:GetDateAndTime()
        end
    end

    local importProfile = (contentType == "PvP" and detailsImportString) or (contentType == "PvE" and detailsImportStringPvE)
    local importName = (contentType == "PvP" and "SkillCapped") or (contentType == "PvE" and "SkillCapped PvE")

    Details:EraseProfile(importName)
    Details:ImportProfile(importProfile, importName, false, false)
    -- if _detalhes_global and _detalhes_global.always_use_profile then
    --     _detalhes_global.always_use_profile = importName
    -- end

    local f = CreateFrame("Frame")
    f:RegisterEvent("PLAYER_LOGOUT")
    f:SetScript("OnEvent", function()
        if _detalhes_global then
            _detalhes_global.always_use_profile = false
            _detalhes_global.always_use_profile_name = importName
        end
    end)
end

function SC:UpdateDetailsProfile(contentType)
    if not Details then return end

    local pvpBackup = "DetailsDBPvP"
    local pveBackup = "DetailsDBPvE"

    local importName = (SkillCappedDB.mainContent == "PvP" and SkillCappedBackupDB[pvpBackup] and "SkillCapped") or (SkillCappedDB.mainContent == "PvE" and SkillCappedBackupDB[pveBackup] and "SkillCapped PvE") or nil

    if importName then
        Details:ApplyProfile(importName)

        local f = CreateFrame("Frame")
        f:RegisterEvent("PLAYER_LOGOUT")
        f:SetScript("OnEvent", function()
            if _detalhes_global then
                _detalhes_global.always_use_profile = false
                _detalhes_global.always_use_profile_name = importName
            end
        end)
    end
end